import hashlib

class BlockHeader:
 def __init__(self, version, previous_block_hash, merkle_root, timestamp, difficulty_target, nonce):
 self.version = version
 self.previous_block_hash = previous_block_hash
 self.merkle_root = merkle_root
 self.timestamp = timestamp
 self.difficulty_target = difficulty_target
 self.nonce = nonce

 def hash(self):
 header_data = str(self.version) + self.previous_block_hash + self.merkle_root + str(self.timestamp) + str(self.difficulty_target) + str(self.nonce)
 return hashlib.sha256(hashlib.sha256(header_data.encode()).digest()).hexdigest()

#include <stdint.h>
#include <string.h>
#include <openssl/sha.h>

typedef struct {
 uint32_t version;
 unsigned char previous_block_hash[32];
 unsigned char merkle_root[32];
 uint32_t timestamp;
 uint32_t difficulty_target;
 uint32_t nonce;
} BlockHeader;

void block_header_hash(BlockHeader* header, unsigned char* hash) {
 unsigned char header_data[80];
 memcpy(header_data, &header->version, 4);
 memcpy(header_data + 4, header->previous_block_hash, 32);
 memcpy(header_data + 36, header->merkle_root, 32);
 memcpy(header_data + 68, &header->timestamp, 4);
 memcpy(header_data + 72, &header->difficulty_target, 4);
 memcpy(header_data + 76, &header->nonce, 4);
 SHA256(header_data, 80, hash);
 SHA256(hash, 32, hash);
}
